 10135→  // Check the simplest things first.  In particular, it's important to
 10136→  // check mIsActive before making any of the more expensive calls such
 10137→  // as GetRootPresContext, for the case of a browser with a large
 10138→  // number of tabs.
 10139→  // Don't bother doing anything if we still have painting suppressed or we are
 10140→  // not active.
 10141→  if (!mIsActive || mPaintingSuppressed || !IsVisible()) {
 10142→    return;
 10143→  }
 10144→
 10145→  nsRootPresContext* rootPresContext = mPresContext->GetRootPresContext();
